
import { config } from './config.js'
import { decryptStsInfo } from './u.js'

let domain = {
  'dev': 'https://ztapi-dev.xiaogj.com',
  'test': 'https://ztapi-test.xiaogj.com',
  'sit': 'https://ztapi-sit.xiaogj.com',
  'prod': 'https://cloudapi.xiaogj.com',
}

// window.domain = domain


/* {
  env: 环境，测试还是生产
  getStsParams: 找业务层获取sts的入参的方法，
  file: ,
  progress: callback 上传进度回调
} */
class Base {
  constructor(opts = {}) {
    this.env = opts.env || config.env
    this.ossConfig = opts.ossConfig || {}

    if (!domain[this.env]) {
      throw Error('请设置正确的环境参数')
    }
    this.isEncrypt = opts.isEncrypt || config.isEncrypt || false
    // 1默认  2时间戳覆盖文件名
    this.fileNameType=opts.fileNameType || config.fileNameType || 1
    
    const rename = opts.file.name.replace(/[+%&$#]/g, '');
    const newFile = new File([opts.file], rename, { type: opts.file.type });
    this.file = newFile;    

    this.getFileType(opts.file.type)

    this.getStsParams = opts.getStsParams || config.getStsParams(this.file)

    if (typeof opts.progress === 'function') {
      this.progress = opts.progress
    }
    if (typeof opts.success === 'function') {
      this.success = opts.success
    }

    this.client = null
  }

  getFileType(typeString) {
    let typeStr, typeNum;
    if (typeString.indexOf('image') === 0) {
      typeStr = 'image';
      typeNum = '1'
    } else if (typeString.indexOf('video') === 0) {
      typeStr = 'video';
      typeNum = '3'
    } else if (typeString.indexOf('audio') === 0) {
      typeStr = 'audio';
      typeNum = '4'
    } else {
      typeStr = 'file';
      typeNum = '2'
    }

    this.fileType = typeNum
    this.fileTypeStr = typeStr
  }

  async getSts() {
    if (this.sts) { return }
    let stsParams = await this.getStsParams()
    
    // 处理业务侧自定义参数
    let busInfo = stsParams.businessDto
    for (const key in busInfo) {
      if (Object.hasOwnProperty.call(busInfo, key)) {
        if (busInfo[key] == null) {
          busInfo[key] = ''
        } else {
          busInfo[key] = '' + busInfo[key]
        }
      }
    }

    let ret = await config.axios({
      baseURL: domain[this.env],
      url: '/file/getStsInfoV'+(this.isEncrypt?'3':'2'),
      method: 'post',
      data: stsParams,
    })
    
    if (ret.data.code !== 200) {
      return Promise.reject(ret.data.data);
    }

    let stsData = ret.data.data;
    if (this.isEncrypt) {
      try {
        stsData = decryptStsInfo(stsData, this.env);
      } catch (error) {
        return Promise.reject('解密STS信息失败: ' + error.message);
      }
    }

    this.sts = stsData

    // 去除文件名中的问号，因为上传问号会导致文件访问不了（已知视频会出问题）
    let newFileName=this.file.name.replace(/\?/g, '_');
    let ext = newFileName.split('.').pop()
    this.customValue = {
      // fileSize: `${this.file.size || ''}`,
      fileName: newFileName,
      name: newFileName,
      fileSuffix: ext,
      fileType: `${this.fileType}`,
      fileUrl: this.sts.fileUrl,
      fileKey: this.sts.fileKey,
      fileId: this.sts.fileId,
      fileDuration: this.file.duration,
      ...busInfo,
    }
    // 1默认  2时间戳覆盖文件名
    if(this.fileNameType===2){
        this.ossFileKey = this.sts.fileKey + `/${Date.now()}.${ext}`;
    }else{
      // this.ossFileKey = this.sts.fileKey + `/${this.file.name || Date.now()}`;
      if (newFileName && newFileName.split('.').length > 1) {
        const fileName = newFileName.split('.').slice(0, -1).join('.');
        this.ossFileKey = this.sts.fileKey + `/${fileName}-${Date.now()}.${ext}`;
      } else {
        this.ossFileKey = this.sts.fileKey + `/${Date.now()}.${ext}`;
      }
    }

  }
}

export default Base;


